Write-Host "        | | | |/ _` |/ __/ _` | '__/ _` |            " -NoNewline -ForegroundColor Cyan
Write-Host "           |" -ForegroundColor DarkCyan
Write-Host "  |" -ForegroundColor DarkCyan -NoNewline
Write-Host "        | |_| | (_| | (_| (_| | | | (_| |            " -NoNewline -ForegroundColor Cyan
Write-Host "           |" -ForegroundColor DarkCyan
