    Write-Host ""

    $_PTqIuVxnmDnEU = @(Get-Process -Name javaw,java -ErrorAction SilentlyContinue)
    if ($_PTqIuVxnmDnEU.Count -eq 0) {
        Write-Host "  [!] Minecraft is not running." -ForegroundColor DarkGray
    } else {
        Write-Host "  [*] Found $($(_PTqIuVxnmDnEU).Count) Minecraft process(es): $($(_PTqIuVxnmDnEU).Id -join ', ')" -ForegroundColor DarkGray
    }

    # DNS cache scan
    Write-Host ""
    Write-Host "  [DNS Cache Scan]" -ForegroundColor Cyan
    $_RulZAecfGPvdt = @{}
    try {
